const receivedAt = new Date().toISOString();
const debugEnabled = flow.get('migration_debug') === true;
const body = msg.payload;

let candidate = body;
if (body && typeof body === 'object' && !Array.isArray(body)) {
    candidate = body.packet ?? body.rawPacket ?? body.raw_packet ?? body.hexPacket ?? body.payload ?? body;
}

const responseMsg = {
    ...msg,
};

if (candidate === null || candidate === undefined || candidate === '') {
    responseMsg.statusCode = 400;
    responseMsg.payload = {
        accepted: false,
        error: 'empty_payload',
        received_at: receivedAt,
    };

    return [responseMsg, {
        payload: {
            stage: 'ingress',
            dropped_reason: 'empty_payload',
            received_at: receivedAt,
        },
    }, null];
}

const processMsg = {
    payload: candidate,
    _meta: {
        source: 'node-red-imoni',
        received_at: receivedAt,
        debug_enabled: debugEnabled,
    },
};

responseMsg.statusCode = 202;
responseMsg.payload = {
    accepted: true,
    received_at: receivedAt,
};

return [responseMsg, null, processMsg];

