function reversePeripheralTypeMap() {
    const reverse = {};
    const map = peripheralTypeMap();
    Object.keys(map).forEach((key) => {
        reverse[map[key]] = key.toUpperCase();
    });

    return reverse;
}

function normalizeDecoded(decoded, unprocessed) {
    const reverseMap = reversePeripheralTypeMap();
    const packetDescriptions = packetTypeMap();
    const packetType = String(decoded.packetType || '').toUpperCase();
    const packetKind = decoded.type || (packetType === '13' ? 'data' : (packetType === '1A' ? 'heartbeat' : 'unsupported'));
    const peripherals = [];

    const peripheralDataArr = decoded.peripheralDataArr && typeof decoded.peripheralDataArr === 'object'
        ? decoded.peripheralDataArr
        : {};

    Object.entries(peripheralDataArr).forEach(([peripheralName, values]) => {
        const peripheralTypeHex = String(decoded.peripheralMeta?.[peripheralName]?.peripheralTypeHex || reverseMap[peripheralName] || '').toUpperCase();
        const entries = Object.entries(values || {}).map(([ioNumber, value]) => ({
            ioNumber: Number(ioNumber),
            rawHex: Array.isArray(value) ? value[1] ?? null : null,
            action: Array.isArray(value) ? value[2] ?? null : null,
            value: Array.isArray(value) ? value[3] ?? null : null,
        })).sort((left, right) => left.ioNumber - right.ioNumber);

        peripherals.push({
            peripheralName,
            peripheralTypeHex,
            values: entries,
        });
    });

    return {
        imei: String(decoded.imei || decoded.deviceId || ''),
        deviceId: String(decoded.deviceId || decoded.imei || ''),
        type: packetKind,
        timestamp: decoded.timestamp || new Date().toISOString(),
        firmwareVersion: String(decoded.firmwareVersion || ''),
        packetType,
        packetDescription: decoded.packetDescription || packetDescriptions[parseInt(packetType || '0', 16)] || 'Unknown',
        segmentCount: String(decoded.segmentCount || peripherals.length.toString(16).padStart(2, '0')).toUpperCase(),
        dataLength: String(decoded.dataLength || ''),
        peripheralDataArr,
        peripheralMeta: decoded.peripheralMeta || {},
        peripherals,
        unprocessed,
    };
}

function decodeImoni(packet) {
    const actionLengths = actionCodeLengths();
    const actionLabels = actionCodeLabels();
    const packetDescriptions = packetTypeMap();
    const peripheralTypes = peripheralTypeMap();

    packet = String(packet || '').replace(/{|}/g, '');

    let imei = '';
    for (let index = 1; index < 31; index += 2) {
        imei += packet[index];
    }

    let years = '';
    let months = '';
    let days = '';
    let hours = '';
    let minutes = '';
    let seconds = '';

    for (let index = 31; index < 38; index += 2) {
        years += packet[index];
    }
    for (let index = 39; index < 42; index += 2) {
        months += packet[index];
    }
    for (let index = 43; index < 46; index += 2) {
        days += packet[index];
    }
    for (let index = 47; index < 50; index += 2) {
        hours += packet[index];
    }
    for (let index = 51; index < 54; index += 2) {
        minutes += packet[index];
    }
    for (let index = 55; index < 58; index += 2) {
        seconds += packet[index];
    }

    const firmwareVersion = packet.substring(58, 60);
    const packetType = packet.substring(60, 62).toUpperCase();
    const segmentCount = packetType === '1C' ? '00' : packet.substring(62, 64).toUpperCase();
    const dataLength = packetType === '1C' ? '00' : packet.substring(64, 68).toUpperCase();
    const packetKind = packetType === '13' ? 'data' : (packetType === '1A' ? 'heartbeat' : 'unsupported');

    const output = {
        imei,
        deviceId: imei,
        type: packetKind,
        timestamp: `${years}/${months}/${days} ${hours}:${minutes}:${seconds}`,
        firmwareVersion,
        packetType,
        packetDescription: packetDescriptions[parseInt(packetType, 16)] || 'Unknown',
        segmentCount,
        dataLength,
        peripheralDataArr: {},
        peripheralMeta: {},
    };

    let segmentStart = 68;
    const totalSegments = parseInt(segmentCount, 16);

    for (let segmentIndex = 0; segmentIndex < totalSegments; segmentIndex += 1) {
        const segmentLength = parseInt(packet.substring(segmentStart + 4, segmentStart + 6), 16);
        const dataUnitCount = parseInt(packet.substring(segmentStart + 2, segmentStart + 4), 16);
        const peripheralTypeHex = packet.substring(segmentStart, segmentStart + 2).toUpperCase();
        const peripheralName = peripheralTypes[peripheralTypeHex] || `Unknown_${peripheralTypeHex}`;

        if (!output.peripheralDataArr[peripheralName]) {
            output.peripheralDataArr[peripheralName] = {};
            output.peripheralMeta[peripheralName] = {
                peripheralName,
                peripheralTypeHex,
            };
        }

        let dataUnitStart = segmentStart + 6;
        for (let dataUnitIndex = 0; dataUnitIndex < dataUnitCount; dataUnitIndex += 1) {
            const actionCode = parseInt(packet.substring(dataUnitStart, dataUnitStart + 2), 16);
            const dataUnitLength = actionLengths[actionCode];
            const actionLabel = actionLabels[actionCode] || 'unknown';
            const dataUnit = packet.substring(dataUnitStart, dataUnitStart + (dataUnitLength * 2));
            const ioId = parseInt(dataUnit.substring(2, 4), 16);
            const ioNumber = packetType === '14' ? (ioId & 0x0f) : (ioId & 0x1f);
            const dataValue = parseInt(dataUnit.substring(4), 16);

            if (dataValue !== 65535) {
                output.peripheralDataArr[peripheralName][ioNumber] = [
                    ioNumber,
                    dataUnit,
                    actionLabel,
                    dataValue,
                ];
            }

            dataUnitStart += dataUnitLength * 2;
        }

        segmentStart += segmentLength * 2;
    }

    return normalizeDecoded(output, packet);
}

const unprocessed = msg.payload;

if (unprocessed && typeof unprocessed === 'object' && !Array.isArray(unprocessed) && unprocessed.peripheralDataArr) {
    msg.payload = normalizeDecoded(unprocessed, unprocessed.unprocessed || msg.unprocessed || unprocessed);
    return msg;
}

msg.payload = decodeImoni(unprocessed);
msg.unprocessed = unprocessed;
return msg;

if (msg.payload && (msg.payload.type === 'data' || msg.payload.type === 'heartbeat')) {
    return [msg, null];
}

return [null, {
