    ? msg.payload.peripherals.find((peripheral) => peripheral.peripheralName?.startsWith('Modbus'))?.peripheralName || null
    : null;

let profile = explicitProfiles[msg.payload.imei] || null;

if (profile === null && peripheralFamily !== null) {
    profile = familyProfiles.Modbus;
}

msg.conversionProfile = profile || {
    name: 'passthrough',
    rules: [],
};

return msg;

function readPath(target, path) {
    return path.split('.').reduce((carry, segment) => carry && Object.prototype.hasOwnProperty.call(carry, segment) ? carry[segment] : undefined, target);
}

function hexToBigEndianFloat(hex, mode) {
    if (hex.length % 2 !== 0) {
        throw new Error('Invalid hex string length.');
    }

    const byteLength = hex.length / 2;
    if (mode === 'bigEndianFloat32' && byteLength !== 4) {
        throw new Error('Expected 4 bytes for float32.');
    }
    if (mode === 'bigEndianFloat64' && byteLength !== 8) {
        throw new Error('Expected 8 bytes for float64.');
    }

    const bytes = [];
    for (let index = 0; index < hex.length; index += 2) {
        bytes.push(parseInt(hex.substring(index, index + 2), 16));
    }

    const view = new DataView(new ArrayBuffer(byteLength));
    bytes.forEach((byte, index) => view.setUint8(index, byte));

    return mode === 'bigEndianFloat64'
        ? view.getFloat64(0, false)
        : view.getFloat32(0, false);
}

function hexToTwosComplement(hex) {
    if (hex.length % 2 !== 0) {
        throw new Error('Invalid hex string length.');
    }

    let binary = '';
    for (let index = 0; index < hex.length; index += 2) {
        binary += parseInt(hex.substring(index, index + 2), 16).toString(2).padStart(8, '0');
    }

    if (binary[0] === '0') {
        return parseInt(binary, 2);
    }

    let flipped = '';
    for (const bit of binary) {
        flipped += bit === '0' ? '1' : '0';
    }

    return -(parseInt(flipped, 2) + 1);
}

const diagnostics = {
    transform_errors: [],
    transform_skips: [],
};

for (const rule of msg.conversionProfile.rules || []) {
    const entry = readPath(msg.payload, rule.path);

    if (!Array.isArray(entry) || !entry[1]) {
        diagnostics.transform_skips.push({
            path: rule.path,
            reason: 'missing_path',
        });
        continue;
    }

    const rawHex = String(entry[1]);
    const prefixBytes = Number(rule.stripPrefixBytes || 0) * 2;
    const strippedHex = rawHex.substring(prefixBytes);

    try {
        let convertedValue = entry[3];

        if (rule.mode === 'bigEndianFloat32' || rule.mode === 'bigEndianFloat64') {
            convertedValue = hexToBigEndianFloat(strippedHex, rule.mode);
        }

        if (rule.mode === 'twosComplement') {
            convertedValue = hexToTwosComplement(strippedHex);
        }

        if (typeof rule.scale === 'number') {
            convertedValue *= rule.scale;
        }

        entry[3] = convertedValue;
    } catch (error) {
        diagnostics.transform_errors.push({
            path: rule.path,
            mode: rule.mode,
            message: error.message,
        });
    }
}

msg.payload.peripherals = (msg.payload.peripherals || []).map((peripheral) => {
    const values = peripheral.values.map((value) => {
        const updatedEntry = readPath(msg.payload, `peripheralDataArr.${peripheral.peripheralName}.${value.ioNumber}`);

        return {
            ...value,
            value: Array.isArray(updatedEntry) ? updatedEntry[3] : value.value,
        };
    });

    return {
        ...peripheral,
        values,
    };
});

msg.diagnostics = {
    ...(msg.diagnostics || {}),
    ...diagnostics,
};

return msg;

const fallbackTopicPrefixByPeripheralType = {
    '00': 'migration/imoni-lite',
    '11': 'migration/ioext1',
    '12': 'migration/ioext2',
};

const sourceRoutedHubImeis = new Set([
    '869244041754866',
    '869244041759568',
    '869244041767199',
    '869244041759279',
]);

const debugEnabled = msg._meta?.debug_enabled === true;
const receivedAt = msg._meta?.received_at || new Date().toISOString();
const payload = msg.payload || {};
const diagnostics = msg.diagnostics || {};
const mqttMessages = [
    {
        topic: 'devices/' + payload.imei + '/presence',
        payload: {
            status: 'online',
            _meta: {
                imei: payload.imei,
                packet_type: payload.packetType,
                packet_description: payload.packetDescription,
                received_at: receivedAt,
                source: 'node-red-imoni',
            },
        },
        qos: 1,
        retain: false,
    },
];

const publishedChildren = [];
const droppedPeripherals = [];
const route = sourceRoutedHubImeis.has(payload.imei)
    ? 'source_peripheral_topics'
    : 'peripheral_children';

for (const peripheral of payload.peripherals || []) {
    if (!peripheral.peripheralTypeHex) {
        droppedPeripherals.push({
            peripheral_name: peripheral.peripheralName,
            reason: 'missing_peripheral_type_hex',
        });
        continue;
    }

    const childPayload = {
        peripheral_name: peripheral.peripheralName,
        peripheral_type_hex: peripheral.peripheralTypeHex,
    };

    for (const value of peripheral.values || []) {
        childPayload['io_' + value.ioNumber + '_value'] = value.value;
        childPayload['io_' + value.ioNumber + '_action'] = value.action;
        childPayload['io_' + value.ioNumber + '_raw_hex'] = value.rawHex;
    }

    if (route === 'source_peripheral_topics') {
        const sourceKey = payload.imei + ':' + peripheral.peripheralTypeHex;
        const sourceTopic = 'migration/source/imoni/' + payload.imei + '/' + peripheral.peripheralTypeHex + '/telemetry';

        childPayload._meta = {
            source: 'node-red-imoni',
            source_adapter: 'imoni',
            source_key: sourceKey,
            hub_imei: payload.imei,
            peripheral_name: peripheral.peripheralName,
            peripheral_type_hex: peripheral.peripheralTypeHex,
            packet_type: payload.packetType,
            packet_description: payload.packetDescription,
            received_at: receivedAt,
            conversion_profile: msg.conversionProfile?.name || 'passthrough',
            transform_errors: diagnostics.transform_errors || [],
            transform_skips: diagnostics.transform_skips || [],
        };

        if (debugEnabled) {
            childPayload._meta.unprocessed = payload.unprocessed;
        }

        mqttMessages.push({
            topic: sourceTopic,
            payload: childPayload,
            qos: 1,
            retain: false,
        });

        publishedChildren.push(sourceKey);

        continue;
    }

    const topicPrefix = fallbackTopicPrefixByPeripheralType[peripheral.peripheralTypeHex];
    if (!topicPrefix) {
        droppedPeripherals.push({
            peripheral_name: peripheral.peripheralName,
            peripheral_type_hex: peripheral.peripheralTypeHex,
            reason: 'unsupported_peripheral_type',
        });
        continue;
    }

    const childExternalId = payload.imei + '-' + peripheral.peripheralTypeHex;
    childPayload._meta = {
        hub_imei: payload.imei,
        child_external_id: childExternalId,
        peripheral_name: peripheral.peripheralName,
        peripheral_type_hex: peripheral.peripheralTypeHex,
        packet_type: payload.packetType,
        packet_description: payload.packetDescription,
        received_at: receivedAt,
        source: 'node-red-imoni',
        conversion_profile: msg.conversionProfile?.name || 'passthrough',
        transform_errors: diagnostics.transform_errors || [],
        transform_skips: diagnostics.transform_skips || [],
    };

    if (debugEnabled) {
        childPayload._meta.unprocessed = payload.unprocessed;
    }

    mqttMessages.push({
        topic: topicPrefix + '/' + childExternalId + '/telemetry',
        payload: childPayload,
        qos: 1,
        retain: false,
    });

    publishedChildren.push(childExternalId);
}

return [mqttMessages, {
    payload: {
        stage: 'normalize',
        imei: payload.imei,
        organization_slug: null,
        route,
        packet_type: payload.packetType,
        published_child_count: publishedChildren.length,
        published_children: publishedChildren,
        dropped_children: [],
        dropped_peripherals: droppedPeripherals,
        transform_errors: diagnostics.transform_errors || [],
        transform_skips: diagnostics.transform_skips || [],
    },
}];
